window.__QUIZ_DATA__=[{"id":"theory>Biology Practical>2008>1>a>i","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Specimen A is a flower. Remove all the stamens and three petals from specimen A leaving the special petal.    Make a drawing 10-12cm long of the remaining parts of specimen A and label fully.","images":["data:image/jpeg;base64,"],"marking_scheme":"Drawing of specimen A/Pride of Barbados flower with stamens and three petals removed","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>1>a>ii","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"what type of ovary is present in specimen A?","images":[],"marking_scheme":"Superior Ovary.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>1>a>iii","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"iii","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Give one reason for your answer in 1(a) (i) above.","images":[],"marking_scheme":"Ovary is located at a higher position than receptacle/on top of receptacle/above point of attachment of other floral parts","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>1>a>iv","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"iv","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Describe the petals and sepals of specimen A.","images":[],"marking_scheme":"Description of petals and sepal:   -Sepals are of the same colour as petals/petaloid.  -Sepals are smaller than petals in size.  -Petals are fan shaped; brightly coloured.  -Standard petals is tubular/flat with marks.  - One sepal is keel shaped.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>1>a>v","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"v","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"What is the function of the special petal?","images":[],"marking_scheme":"It guides insect/bee to the nectar.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>1>a>vi","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"vi","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"State three features of specimen A which have led to the success of flowering plants.","images":[],"marking_scheme":"-Brightly coloured petal attracts insects which pollinate flower  - Large petals which are easily seen.  - Presence of nectar, attract insect which enhance cross pollination leading to variety and survival of the species.  - Sticky stigma to hold pollen grains for pollination.  - Sticky/rough pollen grains to ensure pollination/attachment to insects.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>1>b>i","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"What type of fruit is specimen B?","images":[],"marking_scheme":"Legume/Pod","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>1>b>ii","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"Give two other examples of the fruit type.","images":[],"marking_scheme":"Bean, peas, caesalpinia, crotalaria, Delonix sp., MuCuna.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>1>b>iii","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"iii","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"State the mode of dispersal of specimen B.","images":[],"marking_scheme":"Explosive mechanism","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>1>b>iv","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"iv","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"State two biological importance of the class of fruit to which specimen B belongs.","images":[],"marking_scheme":"- Source of food/protein.   - Fixes nitrogen in the roots/soil.   - Serves as Cover crop/prevents erosion.   - Source of feed for livestock.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>2>a>i","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"i","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"State the class to which specimen C belongs.","images":[],"marking_scheme":"Class of specimen C/Cock","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>2>a>ii","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"ii","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"Give three reasons for placing Specimen C in that class","images":[],"marking_scheme":"- Body covered with feathers.   - Forelimbs modified into wings.   - Mouth modified into beak.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>2>a>iii","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"iii","group":"","topic":"PLANT AND ANIMAL NUTRITION : ANIMAL NUTRITION","question":"State two food items which specimen C feeds on.","images":[],"marking_scheme":"Grains/any named grain; insects; worms; vegetables.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>2>b>i","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"i","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"State two observation of each of specimen C which adapt it to: its mode of feeding","images":[],"marking_scheme":"-short, strong/horny beak for pecking food.   -sharp/strong claws on toes/digit; for Scratching the surface of ground in search for food.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>2>b>ii","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"ii","group":"","topic":"ADAPTATION FOR SURVIVAL AND EVOLUTION : BEHAVIOURAL ADAPTATIONS IN SOCIAL ANIMALS.","question":"State two observation of each of specimen C which adapt it to: locomotion","images":[],"marking_scheme":"- Streamlined shape to reduce air resistance.  - Forelimbs modified into wings for flying.   - Hind limb for walking and running.   -Tail feathers for steering and balancing","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>2>c>i","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"i","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : TRANSMISSION AND EXPRESSION OF CHARACTERISTICS IN ORGANISMS","question":"List three observable characters of specimen C which can be inherited.","images":[],"marking_scheme":"Colour of feather, shape of comb, shape of beak, eye colour, size of comb, body size; colour of wattle.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>2>c>ii","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"ii","group":"","topic":"BIOLOGY OF HEREDITY (GENETICS) : PROBABILITY IN GENETICS (HYBRID FORMATION)","question":"If white feather colour (W) Is dominant in chickens over black feather colour (w),    with the aid of qenetic.diagrams show how it can be determined whether specimen C is homozygous dominant or heterozygous dominant.","images":["data:image/jpeg;base64,"],"marking_scheme":"Back cross white coloured chicken with (genotype, WW;Ww;) with its double recessive parent(ww)  Cross  If offspring are all white specimen C is homozygous white WW. Specimen C is heterozygous white Ww.","marks":"1","difficulty":"3"},{"id":"theory>Biology Practical>2008>3>a>i","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"i","group":"","topic":"FRUITS","question":"Study carefully Specimens H, J, Kand L and use them to answer the following question:    Make a drawing 8-10cm long of the longitudinal section of specimen H and label fully.","images":["data:image/jpeg;base64,"],"marking_scheme":"Drawing of longitudinal section of specimen H","marks":"1","difficulty":"3"},{"id":"theory>Biology Practical>2008>3>a>ii","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"ii","group":"","topic":"FRUITS","question":"What type of fruit is specimen H?","images":[],"marking_scheme":"Berry","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2008>3>a>iii","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"iii","group":"","topic":"FRUITS","question":"State two other examples of the type of fruit to which specimen H belongs.","images":[],"marking_scheme":"Guava, pepper, garden egg. pawpaw, oranges, citrus fruit.","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2008>3>a>iv","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"iv","group":"","topic":"FRUITS","question":"Is specimen H a true fruit or a false fruit?","images":[],"marking_scheme":"True fruit","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>3>a>v","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"v","group":"","topic":"FRUITS","question":"Give one reason for your answer in  3a(iv) above.","images":[],"marking_scheme":"It is developed from fertilized ovary.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>3>a>vi","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"vi","group":"","topic":"FRUITS","question":"State the food classes present in specimen H","images":[],"marking_scheme":"- Vitamins.   -Minerals   -Salts   - Cabohydrates   - Water","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>3>b>i","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"i","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"State one(1) feature common to specimens J, K and L.","images":[],"marking_scheme":"They are all leaves/ they all have leaves.","marks":"1","difficulty":"1"},{"id":"theory>Biology Practical>2008>3>b>ii","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"ii","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"State two observable characteristic features each of specimens J, K and L.","images":[],"marking_scheme":"J/Gloriosa  -Tip of midrib/leaf into a tendril.  - Leaves are sessile/no petiole/leaf stalk,   - Leaf with parallel veins.    J/Pumpkin: Tendril at tne axile of the leaf.    -Hairy leaf  - Net/recticulate venation.  Specimen K/Brvophvllum: Leaf bear buds at notches of margin.  - Leaf is succulent/fleshy/swollen.   - Leaf has waxy surface.    Specimen L/Onion Bulb:   - Presence of swollen leaf bases (witn reserve food).  - Stem reduced to disc like structure,   -Terminal and axilary buds present.  - Presence of leaf scales    -Adventitious roots present.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>3>b>iii","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"iii","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"State the mode of vegetative propagation of specimens K and L.","images":[],"marking_scheme":"K/Bryophylum: Sprouting of adventitous buds; at margins of leaves.    Specimen L/Onion bulb: Terminal/lateral buds, sprout of new aerial shoots.","marks":"1","difficulty":"2"},{"id":"theory>Biology Practical>2008>3>c","subject":"Biology Practical","year":"2008","type":"Practical","sub_label":"c","group":"","topic":"CONCEPT OF LIVING : REPRODUCTION","question":"State the biological significance of specimens K.","images":[],"marking_scheme":"-Vegetative reproduction.   -Storage organ (store water, mineral salts, etc).  -characteristics of parent plant are preserved.   - Can photosynthesize.","marks":"1","difficulty":"2"}];